class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length;
        int[] pos = new int[n];
        for (int i = 0; i < n; i++) {
            pos[row[i]] = i;
        }
        int swaps = 0;
        for (int i = 0; i < n; i += 2) {
            int j = row[i] ^ 1;
            if (row[i + 1] != j) {
                swaps++;
                int idx = pos[j];
                pos[row[i + 1]] = idx;
                pos[j] = i + 1;
                row[i + 1] = j;
            }
        }
        return swaps;
    }
}
